DROP TABLE IF EXISTS order_items CASCADE;
DROP TABLE IF EXISTS orders CASCADE;
DROP TABLE IF EXISTS products CASCADE;
DROP TABLE IF EXISTS carts CASCADE;
DROP TABLE IF EXISTS users CASCADE;
DROP TABLE IF EXISTS inventory_logs CASCADE;

-- Create users table
CREATE TABLE users (
    uid VARCHAR(128) PRIMARY KEY,
    email VARCHAR(255) UNIQUE NOT NULL,
    password VARCHAR(255) NOT NULL,
    fullname VARCHAR(255),
    dob VARCHAR(50),
    phone VARCHAR(50),
    address TEXT,
    nearest_store VARCHAR(50) DEFAULT 'ngt',
    role VARCHAR(50) DEFAULT 'user',
    fido_credential_id TEXT,
    fido_password TEXT,
    has_fido BOOLEAN DEFAULT FALSE,
    tfa_secret TEXT
);

-- Create carts table
CREATE TABLE carts (
    user_id VARCHAR(128) PRIMARY KEY REFERENCES users(uid) ON DELETE CASCADE,
    items JSONB NOT NULL DEFAULT '[]'::jsonb
);

-- Create products table
CREATE TABLE products (
    id VARCHAR(128) PRIMARY KEY,
    pid VARCHAR(50) NOT NULL,
    name VARCHAR(255) NOT NULL,
    type VARCHAR(100),
    stock INT DEFAULT 0,
    price NUMERIC(20, 2) DEFAULT 0.00,
    unit VARCHAR(50),
    branch VARCHAR(50),
    image_url TEXT
);

-- Create orders table
CREATE TABLE orders (
    id VARCHAR(128) PRIMARY KEY,
    user_id VARCHAR(128) REFERENCES users(uid) ON DELETE SET NULL,
    order_id VARCHAR(50) UNIQUE NOT NULL,
    total_amount NUMERIC(20, 2) DEFAULT 0.00,
    status VARCHAR(50) DEFAULT 'success',
    order_date TIMESTAMP WITH TIME ZONE
);

-- Create order_items table
CREATE TABLE order_items (
    id SERIAL PRIMARY KEY,
    order_id VARCHAR(128) REFERENCES orders(id) ON DELETE CASCADE,
    product_name VARCHAR(255),
    price NUMERIC(20, 2),
    quantity INT,
    image_url TEXT
);

-- Create inventory_logs table
CREATE TABLE inventory_logs (
    id SERIAL PRIMARY KEY,
    product_name VARCHAR(255),
    quantity INT,
    type VARCHAR(100),
    user_name VARCHAR(255),
    branch VARCHAR(50),
    timestamp TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

